// // This D-flip-flop stores the value of the D input on the falling edge of the clock signal when the enable signal is low.
module DFlipFlop (
    input wire clk,
    input wire reset,
    input wire enable,
    input wire D,
    output reg Q
);

always @(posedge clk or posedge reset) begin
    if (reset) begin
        Q <= 0;
    end else if (enable) begin
        Q <= D;
    end
end

endmodule
